import React, { useState } from 'react';
import { auditWebsite } from './services/api';

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@200;300;400;500;600;700&family=JetBrains+Mono:wght@300;400;500&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --bg:          #0d0b1a;
    --bg2:         #120f22;
    --surface:     #1a1530;
    --surface2:    #211c3a;
    --border:      rgba(255,255,255,0.08);
    --border-hi:   rgba(255,255,255,0.15);
    --purple:      #7c3aed;
    --purple-light:#a78bfa;
    --cyan:        #22d3ee;
    --pink:        #e879f9;
    --grad:        linear-gradient(135deg, #7c3aed, #22d3ee);
    --grad2:       linear-gradient(135deg, #4f1d96, #0e7490);
    --text:        #f1f0f7;
    --text-muted:  #9490b8;
    --text-dim:    #4a4570;
    --red:         #f87171;
    --orange:      #fb923c;
    --green:       #34d399;
    --mono:        'JetBrains Mono', monospace;
    --sans:        'Outfit', sans-serif;
    --radius:      12px;
    --radius-lg:   20px;
  }

  html { font-size: 15px; }

  body {
    background: var(--bg);
    color: var(--text);
    font-family: var(--sans);
    min-height: 100vh;
    line-height: 1.6;
    -webkit-font-smoothing: antialiased;
    overflow-x: hidden;
  }

  /* ── Background orbs ─────────────────────────────────────────────── */
  .bg-orbs {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    pointer-events: none; z-index: 0; overflow: hidden;
  }
  .orb {
    position: absolute; border-radius: 50%;
    filter: blur(80px); opacity: 0.18;
  }
  .orb1 { width: 600px; height: 600px; background: #7c3aed; top: -200px; left: -100px; animation: drift1 12s ease-in-out infinite alternate; }
  .orb2 { width: 500px; height: 500px; background: #0891b2; top: 40%; right: -150px; animation: drift2 15s ease-in-out infinite alternate; }
  .orb3 { width: 300px; height: 300px; background: #c026d3; bottom: 10%; left: 30%; animation: drift1 10s ease-in-out infinite alternate-reverse; }

  @keyframes drift1 { from { transform: translate(0, 0); } to { transform: translate(40px, 30px); } }
  @keyframes drift2 { from { transform: translate(0, 0); } to { transform: translate(-30px, 40px); } }

  /* ── Layout ──────────────────────────────────────────────────────── */
  .app {
    position: relative; z-index: 1;
    max-width: 960px;
    margin: 0 auto;
    padding: 0 28px 100px;
  }

  /* ── Navbar ──────────────────────────────────────────────────────── */
  .navbar {
    display: flex; align-items: center; justify-content: space-between;
    padding: 24px 0 20px;
    border-bottom: 1px solid var(--border);
    margin-bottom: 72px;
  }
  .nav-logo {
    font-family: var(--sans);
    font-size: 1.2rem;
    font-weight: 600;
    color: var(--text);
    letter-spacing: -0.02em;
  }
  .nav-logo span {
    background: var(--grad);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .nav-badge {
    font-family: var(--mono);
    font-size: 0.65rem;
    font-weight: 400;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--text-muted);
    padding: 6px 14px;
    border: 1px solid var(--border);
    border-radius: 100px;
    background: var(--surface);
  }

  /* ── Hero ────────────────────────────────────────────────────────── */
  .hero { margin-bottom: 56px; }

  .hero-eyebrow {
    font-family: var(--mono);
    font-size: 0.7rem;
    font-weight: 400;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: var(--cyan);
    margin-bottom: 20px;
    display: flex; align-items: center; gap: 10px;
  }
  .hero-eyebrow::before {
    content: '';
    display: block; width: 24px; height: 1px;
    background: var(--cyan);
  }

  .hero h1 {
    font-family: var(--sans);
    font-size: clamp(2.4rem, 5vw, 3.6rem);
    font-weight: 300;
    line-height: 1.1;
    letter-spacing: -0.03em;
    color: var(--text);
    margin-bottom: 20px;
  }

  .hero h1 strong {
    font-weight: 700;
    background: var(--grad);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  .hero-sub {
    font-size: 1rem;
    font-weight: 300;
    color: var(--text-muted);
    max-width: 520px;
    line-height: 1.7;
  }

  /* ── Input ───────────────────────────────────────────────────────── */
  .input-section { margin-bottom: 56px; }

  .input-wrapper {
    position: relative;
    display: flex;
    gap: 12px;
    align-items: center;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 8px 8px 8px 24px;
    transition: border-color 0.25s;
  }

  .input-wrapper:focus-within {
    border-color: rgba(124, 58, 237, 0.6);
    box-shadow: 0 0 0 3px rgba(124, 58, 237, 0.12);
  }

  .url-input {
    flex: 1;
    background: transparent;
    border: none;
    color: var(--text);
    font-family: var(--mono);
    font-size: 0.85rem;
    font-weight: 300;
    outline: none;
    padding: 8px 0;
  }
  .url-input::placeholder { color: var(--text-dim); }

  .audit-btn {
    background: var(--grad);
    color: #fff;
    border: none;
    border-radius: 14px;
    padding: 14px 28px;
    font-family: var(--sans);
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.15s, transform 0.1s;
    white-space: nowrap;
    letter-spacing: 0.01em;
  }
  .audit-btn:hover:not(:disabled) { opacity: 0.88; }
  .audit-btn:active:not(:disabled) { transform: scale(0.98); }
  .audit-btn:disabled { opacity: 0.4; cursor: not-allowed; }

  .error-msg {
    margin-top: 14px;
    padding: 14px 18px;
    background: rgba(248, 113, 113, 0.08);
    border: 1px solid rgba(248, 113, 113, 0.2);
    border-radius: var(--radius);
    color: var(--red);
    font-size: 0.83rem;
    font-family: var(--mono);
  }

  /* ── Loading ─────────────────────────────────────────────────────── */
  .loading {
    display: flex; align-items: center; gap: 16px;
    padding: 32px 0;
    color: var(--text-muted);
    font-family: var(--mono);
    font-size: 0.78rem;
    font-weight: 300;
  }
  .spinner {
    width: 22px; height: 22px;
    border: 2px solid var(--surface2);
    border-top-color: var(--purple-light);
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
    flex-shrink: 0;
  }
  @keyframes spin { to { transform: rotate(360deg); } }

  /* ── Audit meta bar ──────────────────────────────────────────────── */
  .audit-meta {
    display: flex; align-items: center; gap: 16px;
    padding: 16px 22px;
    background: linear-gradient(135deg, rgba(124,58,237,0.12), rgba(34,211,238,0.06));
    border: 1px solid rgba(124,58,237,0.25);
    border-radius: var(--radius);
    margin-bottom: 36px;
    flex-wrap: wrap;
  }
  .audit-meta-dot { width: 8px; height: 8px; border-radius: 50%; background: var(--grad); flex-shrink: 0; }
  .audit-meta-url { font-family: var(--mono); font-size: 0.78rem; color: var(--purple-light); flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-weight: 300; }
  .audit-meta-time { font-family: var(--mono); font-size: 0.7rem; color: var(--text-muted); white-space: nowrap; }

  /* ── Section ─────────────────────────────────────────────────────── */
  .section {
    margin-bottom: 24px;
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    overflow: hidden;
    background: var(--bg2);
  }

  .section-header {
    display: flex; align-items: center; justify-content: space-between;
    padding: 18px 24px;
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    cursor: pointer;
    user-select: none;
    transition: background 0.15s;
  }
  .section-header:hover { background: var(--surface2); }

  .section-title {
    font-family: var(--sans);
    font-size: 0.75rem;
    font-weight: 600;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    color: var(--text-muted);
    display: flex; align-items: center; gap: 10px;
  }

  .s-dot {
    width: 6px; height: 6px; border-radius: 50%;
    background: var(--grad); flex-shrink: 0;
  }
  .s-dot.orange { background: linear-gradient(135deg, #f97316, #e879f9); }
  .s-dot.green  { background: linear-gradient(135deg, #34d399, #22d3ee); }
  .s-dot.red    { background: linear-gradient(135deg, #f87171, #f97316); }

  .chevron { font-size: 0.65rem; color: var(--text-dim); transition: transform 0.2s; }
  .chevron.open { transform: rotate(180deg); }

  .section-body { padding: 24px; }

  /* ── Metrics grid ────────────────────────────────────────────────── */
  .metrics-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
    gap: 12px;
  }

  .metric-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 18px 16px;
    transition: border-color 0.2s, transform 0.15s;
  }
  .metric-card:hover { border-color: var(--border-hi); transform: translateY(-1px); }

  .metric-value {
    font-family: var(--sans);
    font-size: 1.8rem;
    font-weight: 700;
    color: var(--text);
    line-height: 1;
    margin-bottom: 8px;
    letter-spacing: -0.02em;
  }
  .metric-value.warn  { color: var(--orange); }
  .metric-value.bad   { color: var(--red);    }
  .metric-value.good  { color: var(--green);  }

  .metric-label {
    font-size: 0.68rem;
    color: var(--text-dim);
    text-transform: uppercase;
    letter-spacing: 0.08em;
    font-weight: 500;
  }

  /* ── CTA samples ─────────────────────────────────────────────────── */
  .cta-pill {
    display: inline-block;
    font-family: var(--mono);
    font-size: 0.72rem;
    padding: 4px 12px;
    background: rgba(124,58,237,0.1);
    border: 1px solid rgba(124,58,237,0.2);
    border-radius: 100px;
    color: var(--purple-light);
  }

  /* ── SERP preview ────────────────────────────────────────────────── */
  .serp-box {
    margin-top: 20px;
    padding: 18px 20px;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
  }
  .serp-label { font-family: var(--mono); font-size: 0.65rem; color: var(--text-dim); letter-spacing: 0.1em; text-transform: uppercase; margin-bottom: 10px; }
  .serp-title { color: #818cf8; font-size: 1rem; font-weight: 500; margin-bottom: 4px; }
  .serp-desc  { color: #9490b8; font-size: 0.82rem; line-height: 1.55; }

  /* ── Insights grid ───────────────────────────────────────────────── */
  .insights-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 14px;
  }
  @media (max-width: 600px) { .insights-grid { grid-template-columns: 1fr; } }

  .insight-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 18px;
    transition: border-color 0.2s;
  }
  .insight-card:hover { border-color: var(--border-hi); }

  .insight-label {
    font-size: 0.65rem;
    font-weight: 600;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    margin-bottom: 10px;
    background: var(--grad);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }
  .insight-card p {
    font-size: 0.875rem;
    color: var(--text-muted);
    line-height: 1.7;
    font-weight: 300;
  }

  /* ── Recommendations ─────────────────────────────────────────────── */
  .rec-list { display: flex; flex-direction: column; gap: 14px; }

  .rec-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 20px;
    display: grid;
    grid-template-columns: 44px 1fr;
    gap: 16px;
    align-items: start;
    transition: border-color 0.2s, transform 0.15s;
  }
  .rec-card:hover { border-color: var(--border-hi); transform: translateX(2px); }

  .rec-num {
    width: 44px; height: 44px;
    border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-family: var(--sans);
    font-size: 0.8rem;
    font-weight: 700;
    flex-shrink: 0;
    margin-top: 1px;
  }
  .rec-num.p1 { background: rgba(248,113,113,0.1); color: var(--red);    border: 1px solid rgba(248,113,113,0.25); }
  .rec-num.p2 { background: rgba(251,146,60,0.1);  color: var(--orange); border: 1px solid rgba(251,146,60,0.25);  }
  .rec-num.p3 { background: rgba(124,58,237,0.1);  color: var(--purple-light); border: 1px solid rgba(124,58,237,0.25); }
  .rec-num.p4 { background: rgba(52,211,153,0.1);  color: var(--green);  border: 1px solid rgba(52,211,153,0.25);  }
  .rec-num.p5 { background: rgba(148,144,184,0.08); color: var(--text-muted); border: 1px solid var(--border); }

  .rec-title { font-size: 0.9rem; font-weight: 600; color: var(--text); margin-bottom: 6px; }
  .rec-reasoning { font-size: 0.83rem; color: var(--text-muted); line-height: 1.65; margin-bottom: 10px; font-weight: 300; }
  .rec-action {
    font-size: 0.8rem;
    color: var(--cyan);
    font-family: var(--mono);
    padding: 10px 14px;
    background: rgba(34,211,238,0.06);
    border-radius: 8px;
    border-left: 2px solid var(--cyan);
    font-weight: 300;
  }

  /* ── Prompt logs ─────────────────────────────────────────────────── */
  .prompt-tabs {
    display: flex; gap: 2px; margin-bottom: 16px;
    background: var(--surface);
    border-radius: var(--radius);
    padding: 4px;
    border: 1px solid var(--border);
  }
  .prompt-tab {
    flex: 1; padding: 9px 8px; border: none; background: transparent;
    color: var(--text-dim); font-family: var(--mono); font-size: 0.65rem;
    letter-spacing: 0.08em; text-transform: uppercase; cursor: pointer;
    border-radius: 8px; transition: all 0.15s;
  }
  .prompt-tab.active {
    background: var(--surface2);
    color: var(--purple-light);
    border: 1px solid rgba(124,58,237,0.3);
  }

  .log-meta { display: flex; gap: 10px; margin-bottom: 16px; flex-wrap: wrap; }
  .log-chip {
    font-family: var(--mono); font-size: 0.68rem; color: var(--text-muted);
    padding: 5px 12px; background: var(--surface); border: 1px solid var(--border);
    border-radius: 100px;
  }
  .log-chip span { color: var(--purple-light); }

  .prompt-code {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 18px;
    font-family: var(--mono);
    font-size: 0.75rem;
    font-weight: 300;
    color: var(--text-muted);
    white-space: pre-wrap;
    word-break: break-word;
    line-height: 1.8;
    max-height: 420px;
    overflow-y: auto;
  }
  .prompt-code::-webkit-scrollbar { width: 4px; }
  .prompt-code::-webkit-scrollbar-track { background: transparent; }
  .prompt-code::-webkit-scrollbar-thumb { background: var(--surface2); border-radius: 10px; }
`;

function Section({ title, dotColor, children, defaultOpen = true }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="section">
      <div className="section-header" onClick={() => setOpen(!open)}>
        <div className="section-title">
          <span className={`s-dot ${dotColor || ''}`} />
          {title}
        </div>
        <span className={`chevron ${open ? 'open' : ''}`}>▼</span>
      </div>
      {open && <div className="section-body">{children}</div>}
    </div>
  );
}

function MetricCard({ label, value, colorClass }) {
  return (
    <div className="metric-card">
      <div className={`metric-value ${colorClass || ''}`}>{value ?? '—'}</div>
      <div className="metric-label">{label}</div>
    </div>
  );
}

function MetricsDisplay({ metrics }) {
  if (!metrics) return null;
  const altPct = metrics.missingAltPercent;
  const altColor = altPct > 50 ? 'bad' : altPct > 20 ? 'warn' : 'good';
  const h1Color = metrics.h1Count === 0 ? 'bad' : metrics.h1Count > 1 ? 'warn' : '';
  return (
    <Section title="Factual Metrics" defaultOpen={true}>
      <div className="metrics-grid">
        <MetricCard label="Word Count"       value={metrics.wordCount?.toLocaleString()} />
        <MetricCard label="H1 Tags"          value={metrics.h1Count}  colorClass={h1Color} />
        <MetricCard label="H2 Tags"          value={metrics.h2Count} />
        <MetricCard label="H3 Tags"          value={metrics.h3Count} />
        <MetricCard label="CTAs Found"       value={metrics.ctaCount} colorClass={metrics.ctaCount === 0 ? 'bad' : ''} />
        <MetricCard label="Internal Links"   value={metrics.internalLinks} />
        <MetricCard label="External Links"   value={metrics.externalLinks} />
        <MetricCard label="Images"           value={metrics.imageCount} />
        <MetricCard label="Missing Alt Text" value={`${metrics.missingAltCount} (${altPct}%)`} colorClass={altColor} />
        <MetricCard label="Meta Title"       value={metrics.metaTitle ? '✓ Present' : '✗ Missing'} colorClass={metrics.metaTitle ? 'good' : 'bad'} />
        <MetricCard label="Meta Description" value={metrics.metaDescription ? '✓ Present' : '✗ Missing'} colorClass={metrics.metaDescription ? 'good' : 'bad'} />
      </div>
      {metrics.ctaSamples?.length > 0 && (
        <div style={{ marginTop: 20 }}>
          <div style={{ fontFamily: 'var(--mono)', fontSize: '0.65rem', letterSpacing: '0.1em', textTransform: 'uppercase', color: 'var(--text-dim)', marginBottom: 10 }}>CTA Text Samples</div>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            {metrics.ctaSamples.map((cta, i) => <span key={i} className="cta-pill">{cta}</span>)}
          </div>
        </div>
      )}
      {(metrics.metaTitle || metrics.metaDescription) && (
        <div className="serp-box">
          <div className="serp-label">SERP Preview</div>
          {metrics.metaTitle && <div className="serp-title">{metrics.metaTitle}</div>}
          {metrics.metaDescription && <div className="serp-desc">{metrics.metaDescription}</div>}
        </div>
      )}
    </Section>
  );
}

function InsightsDisplay({ ai }) {
  if (!ai) return null;
  const insights = [
    { label: 'SEO Structure',     text: ai.seoAnalysis },
    { label: 'Messaging Clarity', text: ai.messagingClarity },
    { label: 'CTA Analysis',      text: ai.ctaAnalysis },
    { label: 'Content Depth',     text: ai.contentDepth },
    { label: 'UX Concerns',       text: ai.uxConcerns },
  ].filter(i => i.text);
  return (
    <Section title="AI Insights" dotColor="orange" defaultOpen={true}>
      <div className="insights-grid">
        {insights.map((ins, i) => (
          <div className="insight-card" key={i}>
            <div className="insight-label">{ins.label}</div>
            <p>{ins.text}</p>
          </div>
        ))}
      </div>
    </Section>
  );
}

function Recommendations({ recommendations }) {
  if (!recommendations?.length) return null;
  const cls = p => ['p1','p2','p3','p4','p5'][p - 1] || 'p5';
  return (
    <Section title="Recommendations" dotColor="green" defaultOpen={true}>
      <div className="rec-list">
        {recommendations.map((rec, i) => (
          <div className="rec-card" key={i}>
            <div className={`rec-num ${cls(rec.priority)}`}>P{rec.priority}</div>
            <div>
              <div className="rec-title">{rec.title}</div>
              <div className="rec-reasoning">{rec.reasoning}</div>
              <div className="rec-action">→ {rec.action}</div>
            </div>
          </div>
        ))}
      </div>
    </Section>
  );
}

function PromptLogs({ promptLog }) {
  const [activeTab, setActiveTab] = useState('system');
  if (!promptLog) return null;
  const tabs = [
    { id: 'system', label: 'System Prompt', content: promptLog.systemPrompt },
    { id: 'user',   label: 'User Prompt',   content: promptLog.userPrompt },
    { id: 'input',  label: 'Input Data',    content: promptLog.inputData },
    { id: 'output', label: 'Raw Output',    content: promptLog.rawOutput },
  ];
  return (
    <Section title="Prompt Logs / Reasoning Trace" dotColor="red" defaultOpen={false}>
      <div className="log-meta">
        <div className="log-chip">Model: <span>{promptLog.model}</span></div>
        <div className="log-chip">~<span>{promptLog.inputTokensEstimate?.toLocaleString()}</span> tokens</div>
      </div>
      <div className="prompt-tabs">
        {tabs.map(t => (
          <button key={t.id} className={`prompt-tab ${activeTab === t.id ? 'active' : ''}`} onClick={() => setActiveTab(t.id)}>{t.label}</button>
        ))}
      </div>
      <pre className="prompt-code">{tabs.find(t => t.id === activeTab)?.content || '—'}</pre>
    </Section>
  );
}

export default function App() {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const handleSubmit = async () => {
    if (!url.trim()) return;
    setLoading(true); setError(null); setResult(null);
    try {
      setResult(await auditWebsite(url.trim()));
    } catch (err) {
      setError(err.message || 'An unexpected error occurred.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <style>{styles}</style>
      <div className="bg-orbs">
        <div className="orb orb1" />
        <div className="orb orb2" />
        <div className="orb orb3" />
      </div>

      <div className="app">
        {/* Navbar */}
        <nav className="navbar">
          <div className="nav-logo">eight<span>25</span> audit</div>
          <div className="nav-badge">Internal Tool · AI-Powered</div>
        </nav>

        {/* Hero */}
        <div className="hero">
          <div className="hero-eyebrow">Website Intelligence</div>
          <h1>Audit any page.<br /><strong>Instantly.</strong></h1>
          <p className="hero-sub">Extract factual metrics and generate AI-powered insights grounded in real data — SEO, messaging, CTAs, UX, and prioritized recommendations.</p>
        </div>

        {/* Input */}
        <div className="input-section">
          <div className="input-wrapper">
            <input
              className="url-input"
              type="text"
              value={url}
              onChange={e => setUrl(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleSubmit()}
              placeholder="https://yourwebsite.com"
              disabled={loading}
              spellCheck={false}
            />
            <button className="audit-btn" onClick={handleSubmit} disabled={loading || !url.trim()}>
              {loading ? 'Analysing...' : 'Run Audit →'}
            </button>
          </div>
          {error && <div className="error-msg">⚠ {error}</div>}
        </div>

        {loading && (
          <div className="loading">
            <div className="spinner" />
            <span>Scraping page · extracting metrics · generating AI insights…</span>
          </div>
        )}

        {result && (
          <>
            <div className="audit-meta">
              <div className="audit-meta-dot" />
              <div className="audit-meta-url">{result.url}</div>
              <div className="audit-meta-time">Completed in {(result.processingTimeMs / 1000).toFixed(1)}s</div>
            </div>
            <MetricsDisplay metrics={result.metrics} />
            <InsightsDisplay ai={result.ai} />
            <Recommendations recommendations={result.ai?.recommendations} />
            <PromptLogs promptLog={result.promptLog} />
          </>
        )}
      </div>
    </>
  );
}
